#include <stdio.h>
#include <string.h>
#include <ctype.h>

int count_words(const char *s) {
    int words = 0, in_word = 0;
    for (; *s; s++) {
        if (isspace((unsigned char)*s)) {
            in_word = 0;
        } else if (!in_word) {
            in_word = 1;
            words++;
        }
    }
    return words;
}

int main(void) {
    const char *text =
        "Le noyau Linux\n"
        "gere les processus\n"
        "et la memoire\n";
    FILE *f = fmemopen((void *)text, strlen(text), "r");
    if (!f) return 1;
    char line[256];
    int total_lines = 0, total_words = 0;
    while (fgets(line, sizeof(line), f)) {
        line[strcspn(line, "\n")] = 0;
        total_lines++;
        total_words += count_words(line);
    }
    fclose(f);
    printf("Lines: %d\n", total_lines);
    printf("Words: %d\n", total_words);
    return 0;
}

