 * Compter les caractères par ligne avec fgets
 * ================================================= */
void example_count_chars(void) {
    const char *data = "abc\ndefgh\nij\n";
    FILE *f = fmemopen((void *)data, strlen(data), "r");
    if (!f) return;
    char buf[64];
    int linenum = 0;
    while (fgets(buf, sizeof(buf), f)) {
        buf[strcspn(buf, "\n")] = 0;
        linenum++;
        printf("Line %d: %zu chars\n", linenum, strlen(buf));
